mapper.select:
SELECT r.id, r.venue_id, r.user_id, r.reservation_date, r.start_time, r.end_time, r.purpose, r.participants, r.status, r.reviewer_id, r.review_time, r.review_comment, r.create_time, r.update_time
FROM venue_reservation r
INNER JOIN venue v ON r.venue_id = v.id
INNER JOIN user u ON r.user_id = u.id
WHERE 1=1

    AND r.user_id = #{userId}


    AND r.venue_id = #{venueId}


    AND v.name LIKE CONCAT('%', #{venueName}, '%')


    AND u.name LIKE CONCAT('%', #{userName}, '%')


    AND r.status = #{status}


    AND r.start_time >= #{startTime}


    AND r.end_time <= #{endTime}

ORDER BY r.id DESC

SELECT r.*
FROM venue_reservation r
LEFT JOIN venue v ON r.venue_id = v.id
WHERE r.reservation_date BETWEEN #{startDate} AND #{endDate}

    AND r.venue_id = #{venueId}


    AND r.status = #{status}

ORDER BY r.reservation_date DESC, r.start_time DESC
